mapper.select:
SELECT module_idx, module_type, module_name, remark, link_url, link_param, auth_group_id, add_dttm, add_id, mod_dttm, mod_id FROM WB_MODULE_MNGT WHERE module_type = #{module_type}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY module_idx DESC

${pagingTop} SELECT module_idx, module_type, module_name, remark, link_url, link_param, auth_group_id, add_dttm, add_id, mod_dttm, mod_id FROM WB_MODULE_MNGT WHERE module_type = #{module_type}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY MODULE_IDX DESC ${pagingBottom}

SELECT COUNT(*) FROM WB_MODULE_MNGT WHERE module_type = #{module_type}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY MODULE_IDX DESC

mapper.insert:
INSERT INTO CMS_MODULE_TERMS
(
	MODULE_IDX, TERMS_IDX
) VALUES (
	#{module_idx}, #{terms_idx} 
)

mapper.delete:
DELETE FROM
	CMS_MODULE_TERMS
WHERE
	module_idx = #{module_idx}
AND	terms_idx = #{terms_idx}
